// MobileTriggerBuild is the resolver for the mobileTriggerBuild field.
//
// EAS builds are dispatched from the workspace shell via the
// `eas build --no-wait` runtime path (see core/runtime/internal/mobile/
// expo_build.go). The orchestrator-side trigger here picks up the most
// recent non-terminal build for the requested platform and registers
// it with the background poller so the subscription + ledger + artifact
// flow take over.
func (r *mutationResolver) MobileTriggerBuild(ctx context.Context, input model.MobileTriggerBuildInput) (*model.MobileBuild, error) {
	client, project, err := r.mobileClientForProject(ctx, input.ProjectID)
	if err != nil {
		return nil, err
	}
	platform := strings.ToLower(strings.TrimSpace(input.Platform))
	if platform != "ios" && platform != "android" {
		return nil, fmt.Errorf("mobile: invalid platform %q (want ios|android)", input.Platform)
	}
	easProjectID := mobileEASProjectID(project)
	if easProjectID == "" {
		return nil, errors.New("mobile: project has no EAS project id (set MobileStack.EAS.ProjectID)")
	}
	builds, err := client.ListBuilds(ctx, easProjectID, eas.ListBuildsOpts{
		Platform: platform,
		Limit:    10,
	})
	if err != nil {
		return nil, fmt.Errorf("mobile: list builds: %w", err)
	}
	var pick *eas.Build
	for _, b := range builds {
		if b == nil {
			continue
		}
		if !b.Status.Terminal() {
			pick = b
			break
		}
	}
	if pick == nil {
		return nil, errors.New("mobile: no in-flight EAS build to track — dispatch via the workspace shell first")
	}
	if r.EASPoller != nil {
		r.EASPoller.Track(eas.TrackOpts{
			BuildID:   pick.ID,
			ProjectID: project.ID,
			TenantID:  mobileTenantUUID(project),
		})
	}
	return mobileBuildToGraphQL(pick), nil
}

