// MobileSubmitToStore is the resolver for the mobileSubmitToStore field.
func (r *mutationResolver) MobileSubmitToStore(ctx context.Context, input model.MobileSubmitInput) (*model.MobileSubmission, error) {
	client, project, err := r.mobileClientForProject(ctx, input.ProjectID)
	if err != nil {
		return nil, err
	}
	easProjectID := mobileEASProjectID(project)
	if easProjectID == "" {
		return nil, errors.New("mobile: project has no EAS project id (set MobileStack.EAS.ProjectID)")
	}
	platform := strings.ToLower(strings.TrimSpace(input.Platform))
	opts := eas.StoreSubmitOpts{
		Platform:  platform,
		ProjectID: easProjectID,
	}
	switch platform {
	case "ios":
		opts.IOSAppleID = strDeref(input.IosAppleID)
		opts.IOSASCAppID = strDeref(input.IosAscAppID)
		opts.IOSAppleTeamID = strDeref(input.IosAppleTeamID)
		opts.IOSSKU = strDeref(input.IosSku)
		opts.IOSCompanyName = strDeref(input.IosCompanyName)
	case "android":
		opts.AndroidTrack = strDeref(input.AndroidTrack)
		opts.AndroidReleaseStatus = strDeref(input.AndroidReleaseStatus)
		if k := strDeref(input.AndroidServiceAccountKey); k != "" {
			raw, decErr := base64.StdEncoding.DecodeString(k)
			if decErr != nil {
				return nil, fmt.Errorf("mobile: decode androidServiceAccountKey: %w", decErr)
			}
			opts.AndroidServiceAccountKey = raw
		}
	default:
		return nil, fmt.Errorf("mobile: invalid platform %q (want ios|android)", input.Platform)
	}
	sub, err := client.SubmitBuildToStore(ctx, input.BuildID, opts)
	if err != nil {
		return nil, err
	}
	return mobileSubmissionToGraphQL(sub), nil
}

